fix:
void replace() {
  if (firstNode == null || compiler.compilerOptions_.simplifyImports()) {
    // Don't touch the base case ('goog').
    replacementNode = candidateDefinition;
    return;
  }

  if (candidateDefinition != null && explicitNode != null) {
    explicitNode.detachFromParent();
    compiler.reportCodeChange();

    if (NodeUtil.isExpressionNode(candidateDefinition)){

      Node expressionNode=candidateDefinition.getFirstChild();

      Node variableNode=expressionNode.getLastChild();
      expressionNode.removeChild(variableNode);

      Node initializerNode=null;
      while(!expressionNode.isEmpty()){

        initializerNode=expressionNode.getLastChild();

        expressionNode.removeChild(initializerNode);
      }
      ReplaceableNode.asReplaceableNode(initializerNode).unwrapComplexExpressions();
      candidateDefinition.getParent().replaceChild(
          candidateDefinition, initializerNode);
      compiler.reportCodeChange();

    }else {

      replacementNode = candidateDefinition;
      if (NodeUtil.isExpressionNode(candidateDefinition)) {
        candidateDefinition.putBooleanProp(Node.IS_NAMESPACE, true);
        Node assignNode = candidateDefinition.getFirstChild();
        Node nameNode = assignNode.getFirstChild();
        if (nameNode.getType() == Token.NAME) {

          NameReferencingVisitor nrv=new NameReferencingVisitor();
          assignNode.visitChildren(nrv);
          List<Reference> referencesList=nrv.references();
          for(Reference ref:referencesList){

            String name=ref.getName();
            String module=ref.module_;

            if(module.equalsIgnoreCase("")){

              continue;
            }

            boolean shouldAddImportStatement=true;
            Import importInFile=importsInFile.getOrDefault(module, null);
            if(importInFile!=null && importInFile.hasSymbol(name)){

              shouldAddImportStatement=false;
            }

            if(shouldAddImportStatement){

              Import insertionPoint=null;

              int i=0;
              for (;i<importsInFile.size();++i){

                InsertionResult result=insertionOrder.compare(importsInFile.get(i), module);
                if(result==InsertionResult.BEFORE){
                  break;
                }else if(result==InsertionResult.AFTER){

                  continue;
                }
              }
              if (i < importsInFile.size()) {
                throw new IllegalStateException();
              }
              importInFile = new Import();
              importsInFile.add(i, importInFile);
            }
            importInFile.addProviderName(candidateProviderName);
            referenceCountByReferenceId.increment(ref.referenceId_);

            ImportManager.Mark mark=manager.startManage(module);
            manager.markNeededSymbolByReferenceIdAndMark(ref.referenceId_, mark);

          }
        }
      }
    }
  } else {

    if (!firstModule.equals(minimumModule)) {

      String[] names = namespace.split("\\.");
      for (int ii = 0; ii < names.length; ++ii) {
        Import importInFile = importsInFile.getOrDefault(module + names[ii], null);
        if (importInFile != null) {
          break;
        }
        String subNamespace = "";
        for (int jj = ii + 1; jj < names.length; ++jj) {
          subNamespace += "."+names[jj];
        }
        addDependencyOnCurrentScript(module + subNamespace, "goog");
      }
    }

    replacementNode = createDeclarationNode();
    if (explicitNode != null) {
      explicitNode.detachFromParent();
    }
    compiler.reportCodeChange();
  }
}

issue_description:
If there are three modules, the latter two of which depend on the root module:

// Module A
goog.provide('apps');

// Module B
goog.provide('apps.foo.bar.B');

// Module C
goog.provide('apps.foo.bar.C');

and this is compiled in SIMPLE_OPTIMIZATIONS mode, the following code will be produced:

// Module A
var apps={};apps.foo.bar={};apps.foo={};

// Module B
apps.foo.bar.B={};

// Module C
apps.foo.bar.C={};

This will result in a runtime error in Module A because apps.foo.bar is assigned before apps.foo.

The patch for the fix (with regression test) is available at:
http://codereview.appspot.com/2416041

